import java.util.*;

public class Main {
    static class TreeNode {
        int val;
        TreeNode left, right;
        TreeNode(int v) { val = v; }
    }

    static TreeNode build(int[] a, int l, int r) {
        if (l > r) return null;
        int m = l + (r - l) / 2;
        TreeNode node = new TreeNode(a[m]);
        node.left = build(a, l, m - 1);
        node.right = build(a, m + 1, r);
        return node;
    }

    public static void main(String[] args) throws Exception {
        // Read entire input, replace escaped "\n" with spaces, then parse integers.
        String data = new String(System.in.readAllBytes());
        data = data.replace("\\n", " ");
        Scanner sc = new Scanner(data);
        StringBuilder out = new StringBuilder();
        if (!sc.hasNextInt()) {
            System.out.print("");
            return;
        }
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            TreeNode root = build(arr, 0, N - 1);
            out.append("Successfully created BST!");
            if (T > 0) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

